// Reminder Service for managing application reminders
class ReminderService {
  constructor() {
    this.reminders = {
      backup: {
        interval: 2 * 24 * 60 * 60 * 1000, // 2 days in milliseconds
        lastShown: null,
        nextReminder: null,
        storageKey: 'backupReminder'
      },
      machineCount: {
        interval: 24 * 60 * 60 * 1000, // 1 day in milliseconds
        lastShown: null,
        nextReminder: null,
        storageKey: 'machineCountReminder'
      }
    }
  }

  // Initialize reminder service
  init() {
    this.loadReminderState()
    this.scheduleNextReminders()
  }

  // Load reminder state from localStorage
  loadReminderState() {
    Object.keys(this.reminders).forEach(key => {
      const reminder = this.reminders[key]
      const stored = localStorage.getItem(reminder.storageKey)
      
      if (stored) {
        try {
          const data = JSON.parse(stored)
          reminder.lastShown = data.lastShown ? new Date(data.lastShown) : null
          reminder.nextReminder = data.nextReminder ? new Date(data.nextReminder) : null
        } catch (error) {
          console.error(`Error loading ${key} reminder state:`, error)
        }
      }
    })
  }

  // Save reminder state to localStorage
  saveReminderState(reminderType) {
    const reminder = this.reminders[reminderType]
    const data = {
      lastShown: reminder.lastShown ? reminder.lastShown.toISOString() : null,
      nextReminder: reminder.nextReminder ? reminder.nextReminder.toISOString() : null
    }
    localStorage.setItem(reminder.storageKey, JSON.stringify(data))
  }

  // Check if reminder should be shown
  shouldShowReminder(reminderType) {
    const reminder = this.reminders[reminderType]
    const now = new Date()

    // If no next reminder is set, show immediately
    if (!reminder.nextReminder) {
      return true
    }

    // Check if it's time to show the reminder
    return now >= reminder.nextReminder
  }

  // Show reminder and schedule next one
  showReminder(reminderType, action = 'dismiss') {
    const reminder = this.reminders[reminderType]
    const now = new Date()

    reminder.lastShown = now

    // Schedule next reminder based on action
    switch (action) {
      case 'backup':
        // After backup, remind in 2 days
        reminder.nextReminder = new Date(now.getTime() + reminder.interval)
        break
      case 'remind-later':
        // Remind in 4 hours
        reminder.nextReminder = new Date(now.getTime() + 4 * 60 * 60 * 1000)
        break
      case 'dismiss':
        // After dismiss, remind in 2 days
        reminder.nextReminder = new Date(now.getTime() + reminder.interval)
        break
      case 'enter-counts':
        // After entering counts, remind tomorrow
        reminder.nextReminder = new Date(now.getTime() + reminder.interval)
        break
      case 'skip-today':
        // Skip today, remind tomorrow
        reminder.nextReminder = new Date(now.getTime() + reminder.interval)
        break
      default:
        // Default: remind in interval
        reminder.nextReminder = new Date(now.getTime() + reminder.interval)
    }

    this.saveReminderState(reminderType)
  }

  // Schedule next reminders
  scheduleNextReminders() {
    Object.keys(this.reminders).forEach(key => {
      const reminder = this.reminders[key]
      
      if (!reminder.nextReminder) {
        // No reminder scheduled, schedule one for now
        reminder.nextReminder = new Date()
        this.saveReminderState(key)
      }
    })
  }

  // Get days since last backup
  getDaysSinceLastBackup() {
    const reminder = this.reminders.backup
    if (!reminder.lastShown) {
      return null // No backup record
    }
    
    const now = new Date()
    const diffTime = Math.abs(now - reminder.lastShown)
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
    
    return diffDays
  }

  // Check if machine counts have been entered today
  hasTodayMachineCounts() {
    const today = new Date().toISOString().split('T')[0]
    const lastCountDate = localStorage.getItem('lastMachineCountDate')
    
    return lastCountDate === today
  }

  // Mark machine counts as entered for today
  markMachineCountsEntered() {
    const today = new Date().toISOString().split('T')[0]
    localStorage.setItem('lastMachineCountDate', today)
    localStorage.setItem('hasTodayReadings', 'true')
  }

  // Reset machine counts for new day
  resetDailyMachineCounts() {
    const today = new Date().toISOString().split('T')[0]
    const lastCountDate = localStorage.getItem('lastMachineCountDate')
    
    if (lastCountDate !== today) {
      localStorage.removeItem('hasTodayReadings')
    }
  }

  // Get reminder statistics
  getReminderStats() {
    return {
      backup: {
        daysSinceLastBackup: this.getDaysSinceLastBackup(),
        nextBackupDate: this.reminders.backup.nextReminder,
        shouldShow: this.shouldShowReminder('backup')
      },
      machineCount: {
        hasTodayCounts: this.hasTodayMachineCounts(),
        nextReminderDate: this.reminders.machineCount.nextReminder,
        shouldShow: this.shouldShowReminder('machineCount')
      }
    }
  }

  // Clear all reminder data
  clearAllReminders() {
    Object.keys(this.reminders).forEach(key => {
      const reminder = this.reminders[key]
      reminder.lastShown = null
      reminder.nextReminder = null
      localStorage.removeItem(reminder.storageKey)
    })
    
    // Clear related localStorage items
    localStorage.removeItem('lastBackupDate')
    localStorage.removeItem('lastMachineCountDate')
    localStorage.removeItem('hasTodayReadings')
    localStorage.removeItem('lastVisitDate')
    localStorage.removeItem('nextBackupReminder')
  }

  // Force show reminder for testing
  forceShowReminder(reminderType) {
    const reminder = this.reminders[reminderType]
    reminder.nextReminder = new Date()
    this.saveReminderState(reminderType)
  }
}

// Create and export singleton instance
const reminderService = new ReminderService()

export default reminderService
