// Temporary mock authentication setup
// This file should be imported in your main.jsx or App.jsx to set up mock authentication

const setupMockAuth = () => {
  // Set mock authentication token for development
  const mockToken = 'mock-jwt-token'
  localStorage.setItem('authToken', mockToken)
  
  // Set mock user data
  const mockUser = {
    userId: '507f1f77bcf86cd799439011',
    email: 'mock@example.com',
    role: 'admin',
    permissions: ['read', 'write', 'delete']
  }
  localStorage.setItem('user', JSON.stringify(mockUser))
  
  console.log('Mock authentication set up successfully')
}

// Auto-setup mock auth if in development
if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
  setupMockAuth()
}

export default setupMockAuth
