import { Routes, Route } from 'react-router-dom'
import { Toaster } from 'react-hot-toast'
import { Suspense, lazy } from 'react'
import Layout from './components/Layout'
import ErrorBoundary from './components/ErrorBoundary'
import AuthGuard from './components/AuthGuard'
import Login from './pages/Login'

// Lazy load heavy components
const Dashboard = lazy(() => import('./pages/Dashboard'))
const Customers = lazy(() => import('./pages/Customers'))
const CustomerManagement = lazy(() => import('./pages/CustomerManagement'))
const ReminderManagement = lazy(() => import('./pages/ReminderManagement'))
const MachinesUnified = lazy(() => import('./pages/MachinesUnified'))
const Machines = lazy(() => import('./pages/Maintance/Machines'))
const MachinesMaintenance = lazy(() => import('./pages/MachinesMaintenance'))
const Readings = lazy(() => import('./pages/Maintance/Readings'))
const Maintenance = lazy(() => import('./pages/Maintance/Maintenance'))
const Reports = lazy(() => import('./pages/Reports'))
const Settings = lazy(() => import('./pages/Settings'))
const Billing = lazy(() => import('./pages/Billing'))
const NewBill = lazy(() => import('./pages/NewBill'))
const ExpenseManagement = lazy(() => import('./pages/ExpenseManagement'))
const FinancialUnified = lazy(() => import('./pages/FinancialUnified'))
const ExpenseSettings = lazy(() => import('./pages/ExpenseSettings'))
const ProfitLoss = lazy(() => import('./pages/ProfitLoss'))
const BalanceSheet = lazy(() => import('./pages/BalanceSheet'))
const DailySalesExpenseReport = lazy(() => import('./pages/DailySalesExpenseReport'))

// Test components (keep as regular imports for now)
import BillingTest from './components/BillingTest'
import SeparateTableTest from './components/SeparateTableTest'
import SubCategoryPriceTest from './components/SubCategoryPriceTest'
import CustomerPhotoTest from './components/CustomerPhotoTest'
import SubServiceAPITest from './components/SubServiceAPITest'
import Reminder from './pages/Reminder'
import AddBalance from './pages/AddBalance'
import StockManagement from './pages/StockManagement'
import NotificationsPage from './pages/Notifications'
import Bookmarks from './pages/Bookmarks'
const VehicleManagement = lazy(() => import('./pages/VehicleManagement/index.jsx'))

function App() {
  return (
    <ErrorBoundary>
      <Routes>
        {/* Public Routes */}
        <Route path="/login" element={<Login />} />
          
        {/* Protected Routes */}
        <Route path="/*" element={
          <AuthGuard>
            <Layout>
              <Routes>
                <Route path="/" element={<Suspense fallback={<div>Loading...</div>}><Dashboard /></Suspense>} />
                <Route path="/customer-management" element={<Suspense fallback={<div>Loading...</div>}><CustomerManagement /></Suspense>} />
                <Route path="/settings" element={<Suspense fallback={<div>Loading...</div>}><Settings /></Suspense>} />
                <Route path="/reminder-management" element={<Suspense fallback={<div>Loading...</div>}><ReminderManagement /></Suspense>} />
                <Route path="/billing" element={<Suspense fallback={<div>Loading...</div>}><FinancialUnified /></Suspense>} />
                <Route path="/machines" element={<Suspense fallback={<div>Loading...</div>}><MachinesUnified /></Suspense>} />
                <Route path="/stock-management" element={<Suspense fallback={<div>Loading...</div>}><StockManagement /></Suspense>} />
                <Route path="/vehicle-management" element={<Suspense fallback={<div>Loading...</div>}><VehicleManagement /></Suspense>} />
                <Route path="*" element={<Suspense fallback={<div>Loading...</div>}><Settings /></Suspense>} />
              </Routes>
            </Layout>
          </AuthGuard>
        } />
      </Routes>
      <Toaster 
        position="top-right"
        toastOptions={{
          duration: 4000,
          style: {
            background: '#363636',
            color: '#fff',
          },
          success: {
            duration: 3000,
            iconTheme: {
              primary: '#4ade80',
              secondary: '#fff',
            },
          },
          error: {
            duration: 5000,
            iconTheme: {
              primary: '#ef4444',
              secondary: '#fff',
            },
          },
        }}
      />
    </ErrorBoundary>
  )
}

export default App
